/**
 * Translate an Arabic string to English using the dictionary.
 * Returns the original if not found.
 */
export function translateAr(text: string): string {
  if (!text) return text;
  const trimmed = text.trim();
  if (AR_TO_EN[trimmed]) {
    // Preserve leading/trailing whitespace
    const leading = text.match(/^\s*/)?.[0] || "";
    const trailing = text.match(/\s*$/)?.[0] || "";
    return leading + AR_TO_EN[trimmed] + trailing;
  }
  // Try without trailing colon/star/punct
  const m = trimmed.match(/^(.*?)([:*؟?!.]+)$/);
  if (m && AR_TO_EN[m[1].trim()]) return AR_TO_EN[m[1].trim()] + (m[2] || "");
  return text;
}
